using Store;

namespace ShoppingCart.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private Store.ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new Store.ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(19.98m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AccumulatesTotal()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 3, 5.00m);

        Assert.AreEqual(25.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-001", 2, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void AddItem_InvalidSku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    [DataRow(-0.01)]
    public void AddItem_NegativePrice_ThrowsArgumentException(double price)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem("SKU-001", 1, (decimal)price));
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-001", 2, 10.00m);
        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() => _sut.RemoveItem("NO-SUCH"));
    }

    [TestMethod]
    public void RemoveItem_OneOfMany_OnlyRemovesSpecifiedItem()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 1, 20.00m);
        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _sut.CalculateTotal());
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _sut.AddItem("SKU-001", 2, 15.00m);
        _sut.AddItem("SKU-002", 1, 5.00m);
        _sut.RemoveItem("SKU-002");

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    [DataRow("SAVE10", 10)]
    [DataRow("SAVE20", 20)]
    public void ApplyCoupon_ValidCode_ReducesTotal(string code, int discountPercent)
    {
        _sut.AddItem("SKU-001", 1, 100.00m);
        _sut.ApplyCoupon(code);

        decimal expected = 100.00m - (100.00m * discountPercent / 100m);
        Assert.AreEqual(expected, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _sut.AddItem("SKU-001", 1, 50.00m);

        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmpty_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _sut.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }
}

